package main

import (
	"encoding/json"
	"fmt"

	"github.com/hajimehoshi/ebiten/v2"
)

type Tile struct {
	// "wall", "box", "vent_down"
	Type string `json:"type"`
	// used to identify different machines.
	SubType string `json:"subtype"`

	StoredSubtype string

	Inventory map[string]int

	Damage float64
}

type Sublevel struct {
	Title string

	tileMap     *Tilemap
	inGameItems []*InGameItem

	conveyorItems []*ConveyorItem

	adjacentSpaces AdjacentSpaces

	Enemies []*Enemy

	Background *ebiten.Image
	Overlay    *ebiten.Image
	Vignette   *ebiten.Image

	Spawners []*Spawner

	isSafeArea bool

	HasFlowingWater bool
}

type AdjacentSpaces struct {
	North string
	East  string
	South string
	West  string
	Up    string
	Down  string
}

type Spawner struct {
	X    int
	Y    int
	item string
}

type Tilemap = [15][20]*Tile

func TileIsSolid(g *Game, tile *Tile) bool {
	if tile == nil {
		return false
	}

	hasAuth := false
	for _, item := range g.inventory {
		if item == nil {
			continue
		}
		if item.id == "auth_card" {
			hasAuth = true
			break
		}
	}
	if tile.Type == "auth_gate" && hasAuth {
		return false
	}

	return tile.Type == "wall" ||
		tile.Type == "machine" ||
		tile.Type == "electrical_switch" ||
		tile.Type == "escape_ladder" ||
		tile.Type == "wire" ||
		tile.Type == "template_holder" ||
		tile.Type == "auth_gate"
}

func GetTileFromTileMap(tileMap *Tilemap, x, y int) *Tile {
	if x < 0 || x >= 20 || y < 0 || y >= 15 {
		return nil
	}
	return tileMap[y][x]
}

func TileIsAccended(tile *Tile) bool {
	if tile == nil {
		return false
	}
	return tile.Type == "box" || tile.Type == "conveyor_left" || tile.Type == "conveyor_down"
}

func PrintSublevel(g *Game) {
	v, err := json.Marshal(g.CurrentSublevel().tileMap)
	if err != nil {
		panic(err)
	}
	fmt.Println(v)
	fmt.Println(string(v))
}

func LoadTileMapJSON(s string) *Tilemap {
	var t *Tilemap = &[15][20]*Tile{}
	err := json.Unmarshal([]byte(s), t)
	if err != nil {
		fmt.Println(err)
		panic(err)
	}

	return t
}

